import { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { Clock, ArrowRight, ArrowUpRight, BookOpen, Rss, Search } from 'lucide-react';

/* DATA */
const CATS = ['All','Full Stack','Game Dev','UI/UX','DevOps','Careers','News'];
const CAT_META = {
  'Full Stack':  { col:'#0057ff', rgb:'0,87,255',   label:'Full Stack' },
  'Game Dev':    { col:'#7c3aed', rgb:'124,58,237', label:'Game Dev' },
  'UI/UX':       { col:'#db2777', rgb:'219,39,119', label:'UI/UX Design' },
  'DevOps':      { col:'#0891b2', rgb:'8,145,178',  label:'DevOps & Cloud' },
  'Careers':     { col:'#059669', rgb:'5,150,105',  label:'Careers' },
  'News':        { col:'#d97706', rgb:'217,119,6',  label:'Company News' },
};

const POSTS = [
  { slug:'scalable-rest-apis', featured:true, img:'https://images.unsplash.com/photo-1555066931-4365d14bab8c?w=1200&q=85', title:'Building Scalable REST APIs with Node.js', subtitle:'Best practices every engineer should know.', excerpt:'RESTful APIs are the backbone of modern web apps. We break down the patterns our team follows to keep APIs clean, consistent, and production-ready at scale.', cat:'Full Stack', author:'Synnoviq Engineering', date:'Jan 15, 2025', read:'5 min', tags:['Node.js','REST API','Backend','Architecture'] },
  { slug:'unity-vs-unreal-2025', img:'https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?w=900&q=85', title:'Unity vs. Unreal in 2025', subtitle:'Which engine is right for your next game?', excerpt:"Both engines are industry-leading — but serve very different purposes. Here's how our game team approaches the engine decision for every new project.", cat:'Game Dev', author:'Synnoviq Game Studio', date:'Feb 3, 2025', read:'7 min', tags:['Unity','Unreal','Game Design'] },
  { slug:'internship-experience', img:'https://images.unsplash.com/photo-1523240795612-9a054b0db644?w=900&q=85', title:'From Intern to Engineer', subtitle:'What our internship actually looks like.', excerpt:"Our internship isn't about coffee runs. It's about real projects, real code reviews, and real mentorship. Here's a typical week.", cat:'Careers', author:'Synnoviq HR', date:'Mar 10, 2025', read:'4 min', tags:['Internship','Career','Mentorship'] },
  { slug:'ux-conversion-mistakes', img:'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=900&q=85', title:'5 UX Mistakes Killing Conversions', subtitle:"Bad UX costs real revenue — here's the fix.", excerpt:'Our design team walks through the five most common UX mistakes they see in client products and exactly how to fix each one.', cat:'UI/UX', author:'Synnoviq Design', date:'Mar 28, 2025', read:'6 min', tags:['UX','Figma','Conversion'] },
  { slug:'cicd-pipelines', img:'https://images.unsplash.com/photo-1667372393119-3d4c48d07fc9?w=900&q=85', title:'CI/CD Pipelines From Zero', subtitle:'Automated deployment without the headaches.', excerpt:"Continuous integration and deployment can feel overwhelming. Here's how Synnoviq sets up battle-tested pipelines that let teams ship confidently every day.", cat:'DevOps', author:'Synnoviq DevOps', date:'Apr 5, 2025', read:'8 min', tags:['CI/CD','Docker','AWS'] },
  { slug:'game-studio-launch', img:'https://images.unsplash.com/photo-1511512578047-dfb367046420?w=900&q=85', title:'Synnoviq Launches Game Studio', subtitle:'A new chapter in our journey.', excerpt:"We're thrilled to announce the formal launch of our in-house game development studio — what it means for our clients and what we're building next.", cat:'News', author:'Synnoviq Team', date:'Apr 20, 2025', read:'3 min', tags:['Announcement','Game Dev','Studio'] },
  { slug:'react-performance-2025', img:'https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=900&q=85', title:'React Performance in 2025', subtitle:'Profiling, memoisation, and the new compiler.', excerpt:'With React 19 and the compiler in stable, optimisation strategies have shifted. Here is our updated playbook for buttery-smooth React apps.', cat:'Full Stack', author:'Synnoviq Engineering', date:'May 2, 2025', read:'9 min', tags:['React','Performance','Frontend'] },
  { slug:'design-systems-at-scale', img:'https://images.unsplash.com/photo-1581291518857-4e27b48ff24e?w=900&q=85', title:'Design Systems at Scale', subtitle:'Consistency across 10+ products.', excerpt:'A well-built design system is the difference between a product team that ships confidently and one that argues about button colours in every sprint.', cat:'UI/UX', author:'Synnoviq Design', date:'May 18, 2025', read:'6 min', tags:['Design System','Figma','Tokens'] },
  { slug:'kubernetes-for-startups', img:'https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=900&q=85', title:'Kubernetes for Startups', subtitle:"When you need it — and when you don't.", excerpt:"Kubernetes is powerful, but it's not always the right tool. Here's a framework for deciding when to adopt it and how to do so without burning your team out.", cat:'DevOps', author:'Synnoviq DevOps', date:'Jun 1, 2025', read:'7 min', tags:['Kubernetes','DevOps','Cloud'] },
];

/* UTILITIES */
function useScrollProg(ref) {
  const [p, setP] = useState(0);
  useEffect(() => {
    const fn = () => {
      if (!ref.current) return;
      const r = ref.current.getBoundingClientRect();
      setP(Math.min(1, Math.max(0, -r.top / (r.height - window.innerHeight))));
    };
    window.addEventListener('scroll', fn, { passive: true });
    fn();
    return () => window.removeEventListener('scroll', fn);
  }, []);
  return p;
}

function useInView(threshold = 0.1) {
  const ref = useRef(null);
  const [vis, setVis] = useState(false);
  useEffect(() => {
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setVis(true); io.disconnect(); } }, { threshold });
    if (ref.current) io.observe(ref.current);
    return () => io.disconnect();
  }, [threshold]);
  return [ref, vis];
}

/* GRAIN */
function Grain() {
  return (
    <div style={{ position:'fixed', inset:0, zIndex:9999, pointerEvents:'none', opacity:.025 }}>
      <svg width="100%" height="100%"><filter id="bg2"><feTurbulence type="fractalNoise" baseFrequency="0.65" numOctaves="3" stitchTiles="stitch"/><feColorMatrix type="saturate" values="0"/></filter><rect width="100%" height="100%" filter="url(#bg2)"/></svg>
    </div>
  );
}

function ProgressBar() {
  const [p, setP] = useState(0);
  useEffect(() => {
    const fn = () => { const d = document.documentElement; setP(d.scrollTop / (d.scrollHeight - d.clientHeight)); };
    window.addEventListener('scroll', fn, { passive: true });
    return () => window.removeEventListener('scroll', fn);
  }, []);
  return (
    <div style={{ position:'fixed', top:0, left:0, right:0, height:3, zIndex:9999, background:'rgba(0,0,0,.1)' }}>
      <div style={{ height:'100%', width:'100%', background:'linear-gradient(90deg,#0057ff,#7c3aed,#db2777)', transformOrigin:'left', transform:`scaleX(${p})`, transition:'none', willChange:'transform' }} />
    </div>
  );
}

/* HERO */
function Hero() {
  const wRef = useRef(null);
  const prog = useScrollProg(wRef);
  const o = 1 - prog * 2.4;

  return (
    <div ref={wRef} style={{ height:'160vh', position:'relative' }}>
      <section style={{ position:'sticky', top:0, height:'100vh', overflow:'hidden', background:'#020810' }}>
        <div style={{ position:'absolute', inset:'-10% 0', transform:`translateY(${prog * 130}px) translateZ(0)`, willChange:'transform', transition:'none' }}>
          <img src="https://images.unsplash.com/photo-1499750310107-5fef28a66643?w=1800&q=75" alt=""
            style={{ width:'100%', height:'100%', objectFit:'cover', filter:'saturate(.35) brightness(.2)' }} />
        </div>
        <div style={{ position:'absolute', inset:0, background:'linear-gradient(to bottom, rgba(2,8,16,.2) 0%, rgba(2,8,16,.55) 60%, #020810 100%)', pointerEvents:'none' }} />
        <div style={{ position:'absolute', inset:0, background:'radial-gradient(ellipse at 65% 40%, rgba(0,87,255,.1) 0%, transparent 55%)', pointerEvents:'none' }} />

        {/* Decorative grid lines */}
        {[20,40,60,80].map(pct => (
          <div key={pct} style={{ position:'absolute', top:0, bottom:0, left:`${pct}%`, width:1, background:'rgba(255,255,255,.025)', pointerEvents:'none' }} />
        ))}

        <div style={{ position:'absolute', inset:0, display:'flex', flexDirection:'column', justifyContent:'center', padding:'0 clamp(24px,7vw,100px)', opacity:Math.max(0,o), transition:'none', willChange:'opacity' }}>
          <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:24, animation:'bIn .7s .05s both' }}>
            <Rss size={12} color="#0057ff" />
            <span style={{ fontSize:'.6rem', fontWeight:700, letterSpacing:'.24em', textTransform:'uppercase', color:'rgba(255,255,255,.38)' }}>Synnoviq Blog</span>
            <div style={{ width:36, height:1, background:'rgba(255,255,255,.15)' }} />
          </div>

          <h1 style={{ fontFamily:'var(--serif)', fontSize:'clamp(3.8rem,10.5vw,10rem)', fontWeight:900, color:'#fff', letterSpacing:'-.058em', lineHeight:.88, margin:'0 0 28px', animation:'bIn .85s .12s both' }}>
            Tech<br/>
            <span style={{ color:'transparent', WebkitTextStroke:'1.5px rgba(255,255,255,.22)', fontStyle:'italic' }}>Insights</span><br/>
            &amp; Stories.
          </h1>

          <p style={{ fontSize:'clamp(.9rem,1.5vw,1.05rem)', color:'rgba(255,255,255,.4)', maxWidth:380, lineHeight:1.88, marginBottom:44, animation:'bIn .85s .25s both' }}>
            Tutorials, deep-dives &amp; industry perspectives — written by the engineers and designers at Synnoviq.
          </p>

          <div style={{ display:'flex', gap:40, animation:'bIn .85s .38s both' }}>
            {[['9+','Articles'],['6','Categories'],['2025','Latest']].map(([n,l]) => (
              <div key={l}>
                <div style={{ fontFamily:'var(--serif)', fontSize:'clamp(1.5rem,2.8vw,2rem)', fontWeight:900, color:'#fff', letterSpacing:'-.04em', lineHeight:1 }}>{n}</div>
                <div style={{ fontSize:'.58rem', fontWeight:700, letterSpacing:'.14em', textTransform:'uppercase', color:'rgba(255,255,255,.28)', marginTop:5 }}>{l}</div>
              </div>
            ))}
          </div>
        </div>

        <div style={{ position:'absolute', bottom:32, left:'50%', transform:'translateX(-50%)', display:'flex', flexDirection:'column', alignItems:'center', gap:6, opacity:Math.max(0,1-prog*6) }}>
          <div style={{ width:1, height:44, background:'linear-gradient(to bottom,transparent,rgba(255,255,255,.28))', animation:'lineP 2s ease-in-out infinite' }} />
          <span style={{ fontSize:'.5rem', letterSpacing:'.2em', textTransform:'uppercase', color:'rgba(255,255,255,.22)' }}>scroll</span>
        </div>
      </section>
    </div>
  );
}

/* FEATURED */
function Featured() {
  const [ref, vis] = useInView(0.12);
  const [hov, setHov] = useState(false);
  const post = POSTS.find(p => p.featured);
  const meta = CAT_META[post.cat];

  return (
    <section style={{ background:'#020810', paddingBottom:0 }}>
      <div className="wrap" style={{ paddingTop:80 }}>
        <div ref={ref} style={{ display:'flex', alignItems:'center', gap:14, marginBottom:32, opacity:vis?1:0, transform:vis?'none':'translateY(18px)', transition:'opacity .6s ease, transform .6s ease' }}>
          <div style={{ width:32, height:2, borderRadius:1, background:'#0057ff' }} />
          <span style={{ fontSize:'.6rem', fontWeight:700, letterSpacing:'.22em', textTransform:'uppercase', color:'rgba(255,255,255,.32)' }}>Featured Post</span>
        </div>

        <Link to={`/blog/${post.slug}`}
          className="feat-card"
          onMouseEnter={() => setHov(true)}
          onMouseLeave={() => setHov(false)}
          style={{ display:'grid', borderRadius:22, overflow:'hidden', border:`1px solid rgba(${meta.rgb},.22)`, textDecoration:'none', opacity:vis?1:0, transform:vis?(hov?'translateY(-5px)':'translateY(0)'):'translateY(24px)', transition:'opacity .7s .1s ease, transform .5s ease, box-shadow .4s ease', boxShadow: hov?`0 48px 96px rgba(0,0,0,.65),0 0 0 1px rgba(${meta.rgb},.4)`:'0 16px 48px rgba(0,0,0,.4)' }}>

          {/* Image side */}
          <div style={{ position:'relative', overflow:'hidden', minHeight:440 }}>
            <img src={post.img} alt={post.title}
              style={{ position:'absolute', inset:0, width:'100%', height:'112%', objectFit:'cover', filter:'saturate(.65) brightness(.55)', transform:hov?'scale(1.06) translateZ(0)':'scale(1) translateZ(0)', transition:'transform .8s cubic-bezier(.16,1,.3,1)', willChange:'transform' }} />
            <div style={{ position:'absolute', inset:0, background:`linear-gradient(130deg,rgba(${meta.rgb},.28) 0%,transparent 55%)` }} />
            <div style={{ position:'absolute', inset:0, background:'linear-gradient(to right,transparent 55%,#04080f 100%)' }} />
            <div style={{ position:'absolute', top:24, left:24, padding:'6px 16px', borderRadius:999, background:`rgba(${meta.rgb},.22)`, backdropFilter:'blur(12px)', border:`1px solid rgba(${meta.rgb},.5)`, fontSize:'.6rem', fontWeight:700, letterSpacing:'.12em', textTransform:'uppercase', color:'#fff' }}>{meta.label}</div>
          </div>

          {/* Text side */}
          <div style={{ background:'#04080f', padding:'clamp(32px,5vw,52px)', display:'flex', flexDirection:'column', justifyContent:'center' }}>
            <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:22 }}>
              <Clock size={12} color="rgba(255,255,255,.3)" />
              <span style={{ fontSize:'.66rem', color:'rgba(255,255,255,.3)', fontWeight:600 }}>{post.read} read · {post.date}</span>
            </div>
            <h2 style={{ fontFamily:'var(--serif)', fontSize:'clamp(1.7rem,3vw,2.5rem)', fontWeight:900, color:'#fff', letterSpacing:'-.035em', lineHeight:1.08, marginBottom:12 }}>{post.title}</h2>
            <p style={{ fontSize:'.9rem', color: meta.col, fontWeight:600, marginBottom:16 }}>{post.subtitle}</p>
            <p style={{ fontSize:'.92rem', color:'rgba(255,255,255,.48)', lineHeight:1.86, marginBottom:28 }}>{post.excerpt}</p>
            <div style={{ display:'flex', gap:6, flexWrap:'wrap', marginBottom:28 }}>
              {post.tags.map(t => <span key={t} style={{ padding:'4px 11px', borderRadius:999, background:'rgba(255,255,255,.06)', border:'1px solid rgba(255,255,255,.09)', fontSize:'.6rem', fontWeight:600, color:'rgba(255,255,255,.45)' }}>{t}</span>)}
            </div>
            <div style={{ display:'inline-flex', alignItems:'center', gap:9, padding:'12px 22px', borderRadius:11, background:meta.col, color:'#fff', fontWeight:700, fontSize:'.83rem', alignSelf:'flex-start', boxShadow:`0 8px 24px rgba(${meta.rgb},.4)`, transform:hov?'translateX(5px)':'none', transition:'transform .3s ease' }}>
              Read Article <ArrowRight size={13} />
            </div>
          </div>
        </Link>
      </div>
    </section>
  );
}

/* BLOG CARD */
function BlogCard({ post, i }) {
  const [ref, vis] = useInView(0.08);
  const [hov, setHov] = useState(false);
  const meta = CAT_META[post.cat] || { col:'#0057ff', rgb:'0,87,255', label:post.cat };

  return (
    <article ref={ref} onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}
      style={{ borderRadius:18, overflow:'hidden', background:'#0a1628', border: hov?`1px solid rgba(${meta.rgb},.38)`:'1px solid rgba(255,255,255,.07)', boxShadow: hov?`0 32px 64px rgba(0,0,0,.55),0 0 0 1px rgba(${meta.rgb},.18)`:'0 4px 24px rgba(0,0,0,.28)', transform: vis?(hov?'translateY(-8px) translateZ(0)':'translateY(0) translateZ(0)'):'translateY(60px) translateZ(0)', opacity:vis?1:0, transition:`opacity .6s cubic-bezier(.16,1,.3,1) ${i*.09}s, transform .6s cubic-bezier(.16,1,.3,1) ${i*.09}s, border-color .22s ease, box-shadow .22s ease`, willChange:'opacity,transform', display:'flex', flexDirection:'column', cursor:'pointer' }}>

      <div style={{ position:'relative', height:210, overflow:'hidden', flexShrink:0 }}>
        <img src={post.img} alt={post.title}
          style={{ position:'absolute', inset:0, width:'100%', height:'116%', objectFit:'cover', filter:'saturate(.55) brightness(.48)', transform:hov?'scale(1.09) translateZ(0)':'scale(1) translateZ(0)', transition:'transform .75s cubic-bezier(.16,1,.3,1)', willChange:'transform' }} />
        <div style={{ position:'absolute', inset:0, background:`rgba(${meta.rgb},.22)`, mixBlendMode:'multiply', opacity:hov?.9:.45, transition:'opacity .4s ease' }} />
        <div style={{ position:'absolute', inset:0, background:'linear-gradient(to bottom,transparent 30%,#0a1628 100%)' }} />
        <div style={{ position:'absolute', top:14, left:14, padding:'5px 12px', borderRadius:999, background:`rgba(${meta.rgb},.2)`, backdropFilter:'blur(10px)', border:`1px solid rgba(${meta.rgb},.45)`, fontSize:'.56rem', fontWeight:700, letterSpacing:'.1em', textTransform:'uppercase', color:'#fff' }}>{meta.label}</div>
        <div style={{ position:'absolute', top:14, right:14, display:'flex', alignItems:'center', gap:4, padding:'5px 9px', borderRadius:999, background:'rgba(0,0,0,.42)', backdropFilter:'blur(8px)' }}>
          <Clock size={9} color="rgba(255,255,255,.55)" />
          <span style={{ fontSize:'.56rem', fontWeight:600, color:'rgba(255,255,255,.55)' }}>{post.read}</span>
        </div>
      </div>

      <div style={{ padding:'22px 22px 26px', flex:1, display:'flex', flexDirection:'column' }}>
        <div style={{ fontSize:'.58rem', fontWeight:600, color:'rgba(255,255,255,.22)', letterSpacing:'.1em', marginBottom:10 }}>{post.date}</div>
        <h3 style={{ fontFamily:'var(--serif)', fontSize:'clamp(1.05rem,1.6vw,1.28rem)', fontWeight:800, color:'#fff', letterSpacing:'-.02em', lineHeight:1.2, marginBottom:7, flex:1 }}>{post.title}</h3>
        <p style={{ fontSize:'.78rem', color:meta.col, fontWeight:600, marginBottom:10, letterSpacing:'-.01em' }}>{post.subtitle}</p>
        <p style={{ fontSize:'.84rem', color:'rgba(255,255,255,.42)', lineHeight:1.76, marginBottom:18, display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical', overflow:'hidden' }}>{post.excerpt}</p>
        <div style={{ display:'flex', gap:5, flexWrap:'wrap', marginBottom:18 }}>
          {post.tags.slice(0,3).map(t => <span key={t} style={{ padding:'3px 9px', borderRadius:999, background:'rgba(255,255,255,.05)', border:'1px solid rgba(255,255,255,.08)', fontSize:'.56rem', fontWeight:600, color:'rgba(255,255,255,.38)' }}>{t}</span>)}
        </div>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', borderTop:'1px solid rgba(255,255,255,.06)', paddingTop:14 }}>
          <span style={{ fontSize:'.67rem', color:'rgba(255,255,255,.28)', fontWeight:500 }}>{post.author}</span>
          <Link to={`/blog/${post.slug}`}
            style={{ display:'flex', alignItems:'center', justifyContent:'center', width:30, height:30, borderRadius:'50%', background:hov?meta.col:'rgba(255,255,255,.08)', color:'#fff', transition:'background .25s ease', textDecoration:'none', flexShrink:0 }}>
            <ArrowUpRight size={13} />
          </Link>
        </div>
      </div>
    </article>
  );
}

/* TICKER */
function Ticker() {
  const words = ['Full Stack Engineering','·','Game Development','·','UI/UX Design','·','DevOps & Cloud','·','Careers','·','Company News','·'];
  return (
    <div style={{ overflow:'hidden', background:'#0057ff', padding:'13px 0', margin:'72px 0 0' }}>
      <div style={{ display:'flex', gap:28, animation:'tickL 20s linear infinite', whiteSpace:'nowrap', willChange:'transform' }}>
        {[...words,...words,...words].map((w,i) => <span key={i} style={{ fontSize:'.7rem', fontWeight:700, letterSpacing:'.14em', textTransform:'uppercase', color:'rgba(255,255,255,.82)', flexShrink:0 }}>{w}</span>)}
      </div>
    </div>
  );
}

/* NEWSLETTER */
function Newsletter() {
  const [ref, vis] = useInView(0.15);
  const [email, setEmail] = useState('');
  const [sent, setSent] = useState(false);

  return (
    <section style={{ background:'#020810', padding:'100px 0', position:'relative', overflow:'hidden', borderTop:'1px solid rgba(255,255,255,.05)' }}>
      <div style={{ position:'absolute', top:'50%', left:'50%', transform:'translate(-50%,-50%)', width:'70vw', height:'50vw', borderRadius:'50%', background:'radial-gradient(ellipse,rgba(0,87,255,.07) 0%,transparent 70%)', pointerEvents:'none' }} />
      <div className="wrap" style={{ position:'relative', zIndex:1 }}>
        <div ref={ref} style={{ maxWidth:580, margin:'0 auto', textAlign:'center', opacity:vis?1:0, transform:vis?'none':'translateY(32px)', transition:'opacity .8s ease, transform .8s ease' }}>
          <div style={{ display:'inline-flex', alignItems:'center', gap:7, padding:'6px 15px', borderRadius:999, background:'rgba(0,87,255,.1)', border:'1px solid rgba(0,87,255,.28)', fontSize:'.6rem', fontWeight:700, letterSpacing:'.18em', textTransform:'uppercase', color:'rgba(90,168,255,.9)', marginBottom:22 }}>
            <Rss size={10} /> Stay Updated
          </div>
          <h2 style={{ fontFamily:'var(--serif)', fontSize:'clamp(2rem,5vw,3.4rem)', fontWeight:900, color:'#fff', letterSpacing:'-.04em', lineHeight:1.05, marginBottom:14 }}>
            Never miss a <span style={{ color:'#5aa8ff', fontStyle:'italic' }}>post.</span>
          </h2>
          <p style={{ fontSize:'.92rem', color:'rgba(255,255,255,.4)', lineHeight:1.85, marginBottom:32 }}>
            Get our latest tutorials, case studies, and insights delivered to your inbox. No spam — ever.
          </p>
          {sent ? (
            <div style={{ display:'inline-flex', alignItems:'center', gap:9, padding:'14px 26px', borderRadius:12, background:'rgba(5,150,105,.14)', border:'1px solid rgba(5,150,105,.38)', color:'#34d399', fontWeight:700, fontSize:'.88rem' }}>✓ You&#39;re subscribed — welcome aboard!</div>
          ) : (
            <div style={{ display:'flex', gap:9, maxWidth:420, margin:'0 auto' }}>
              <input value={email} onChange={e => setEmail(e.target.value)} placeholder="your@email.com"
                style={{ flex:1, padding:'13px 16px', borderRadius:11, background:'rgba(255,255,255,.07)', border:'1px solid rgba(255,255,255,.11)', color:'#fff', fontSize:'.86rem', outline:'none', fontFamily:'var(--sans)' }} />
              <button onClick={() => { if(email) setSent(true); }}
                style={{ padding:'13px 22px', borderRadius:11, background:'#0057ff', color:'#fff', fontWeight:700, fontSize:'.86rem', border:'none', cursor:'pointer', whiteSpace:'nowrap', boxShadow:'0 6px 22px rgba(0,87,255,.42)', transition:'transform .2s ease, box-shadow .2s ease', fontFamily:'var(--sans)' }}
                onMouseEnter={e => { e.currentTarget.style.transform='translateY(-2px)'; e.currentTarget.style.boxShadow='0 12px 28px rgba(0,87,255,.58)'; }}
                onMouseLeave={e => { e.currentTarget.style.transform=''; e.currentTarget.style.boxShadow='0 6px 22px rgba(0,87,255,.42)'; }}>
                Subscribe
              </button>
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

/* ROOT */
export default function Blog() {
  const [activeCat, setActiveCat] = useState('All');
  const [search, setSearch] = useState('');
  const [catRef, catVis] = useInView(0.05);

  const filtered = POSTS.filter(p => {
    const matchCat = activeCat === 'All' || p.cat === activeCat;
    const q = search.toLowerCase();
    const matchSearch = !q || p.title.toLowerCase().includes(q) || p.excerpt.toLowerCase().includes(q);
    return matchCat && matchSearch && !p.featured;
  });

  return (
    <div style={{ background:'#020810', minHeight:'100vh' }}>
      <Grain />
      <ProgressBar />
      <Hero />
      <Featured />

      {/* Sticky filter bar */}
      <div style={{ background:'rgba(2,8,16,.92)', position:'sticky', top:0, zIndex:50, borderBottom:'1px solid rgba(255,255,255,.06)', backdropFilter:'blur(20px)' }}>
        <div className="wrap" style={{ paddingTop:0, paddingBottom:0 }}>
          <div ref={catRef} style={{ display:'flex', alignItems:'center', gap:0, overflowX:'auto', scrollbarWidth:'none', padding:'14px 0', opacity:catVis?1:0, transform:catVis?'none':'translateY(-10px)', transition:'opacity .5s ease, transform .5s ease' }}>
            <div style={{ display:'flex', alignItems:'center', gap:8, padding:'7px 13px', borderRadius:9, background:'rgba(255,255,255,.06)', border:'1px solid rgba(255,255,255,.09)', marginRight:14, flexShrink:0 }}>
              <Search size={12} color="rgba(255,255,255,.38)" />
              <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search…"
                style={{ background:'transparent', border:'none', outline:'none', color:'#fff', fontSize:'.75rem', width:110, fontFamily:'var(--sans)' }} />
            </div>
            <div style={{ width:1, height:18, background:'rgba(255,255,255,.09)', marginRight:14, flexShrink:0 }} />
            <div style={{ display:'flex', gap:5, flexShrink:0 }}>
              {CATS.map(c => {
                const meta = CAT_META[c];
                const isA = activeCat === c;
                return (
                  <button key={c} onClick={() => setActiveCat(c)} style={{ padding:'6px 14px', borderRadius:999, border:'none', cursor:'pointer', background:isA?(meta?meta.col:'rgba(255,255,255,.9)'):'rgba(255,255,255,.06)', color:isA?'#fff':'rgba(255,255,255,.48)', fontSize:'.7rem', fontWeight:700, letterSpacing:'.04em', transition:'all .2s ease', whiteSpace:'nowrap', fontFamily:'var(--sans)', boxShadow:isA&&meta?`0 4px 14px rgba(${meta.rgb},.38)`:'none' }}>
                    {c}
                  </button>
                );
              })}
            </div>
            <div style={{ marginLeft:'auto', fontSize:'.62rem', fontWeight:600, color:'rgba(255,255,255,.22)', whiteSpace:'nowrap', paddingLeft:14, flexShrink:0 }}>
              {filtered.length} post{filtered.length !== 1 ? 's' : ''}
            </div>
          </div>
        </div>
      </div>

      {/* Grid */}
      <section style={{ background:'#020810', padding:'64px 0 100px' }}>
        <div className="wrap">
          {filtered.length > 0 ? (
            <div className="blog-grid">
              {filtered.map((post, i) => <BlogCard key={post.slug} post={post} i={i} />)}
            </div>
          ) : (
            <div style={{ textAlign:'center', padding:'80px 0' }}>
              <BookOpen size={36} color="rgba(255,255,255,.1)" style={{ marginBottom:18 }} />
              <p style={{ color:'rgba(255,255,255,.28)', fontSize:'.95rem' }}>No posts found.</p>
            </div>
          )}
        </div>
      </section>

      <Ticker />
      <Newsletter />

      <style>{`
        @keyframes bIn    { from{opacity:0;transform:translateY(26px)} to{opacity:1;transform:none} }
        @keyframes tickL  { from{transform:translateX(0)} to{transform:translateX(-33.33%)} }
        @keyframes lineP  { 0%,100%{opacity:.28} 50%{opacity:.7} }
        .blog-grid { display:grid; grid-template-columns:1fr; gap:22px; }
        @media(min-width:580px){ .blog-grid { grid-template-columns:repeat(2,1fr); } }
        @media(min-width:960px){ .blog-grid { grid-template-columns:repeat(3,1fr); } }
        .feat-card { grid-template-columns:1fr !important; }
        @media(min-width:768px){ .feat-card { grid-template-columns:1fr 1fr !important; } }
        input::placeholder { color:rgba(255,255,255,.28); }
        ::-webkit-scrollbar { display:none; }
      `}</style>
    </div>
  );
}
